package com.chaobo.scm.supplier.domain.qualification;
import com.chaobo.scm.common.error.BusinessException;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import org.junit.jupiter.api.Test;import java.time.*;import java.util.concurrent.atomic.*;import static org.assertj.core.api.Assertions.*;
class SupplierQualificationAggregateTest {private final Ids ids=new Ids();private SupplierQualificationAggregate qualification(){return SupplierQualificationAggregate.submit(1,"BUSINESS_LICENSE","91310000",LocalDate.now().minusDays(1),LocalDate.now().plusDays(30),"https://example/license.pdf",1,ids);}@Test void shouldApproveValidQualification(){var a=qualification();a.approve("资料齐全",2,ids);assertThat(a.status()).isEqualTo(QualificationStatus.VALID);assertThat(a.pullEvents()).hasSize(2);}@Test void shouldRejectWithoutReason(){var a=qualification();assertThatThrownBy(()->a.reject("",2,ids)).isInstanceOf(BusinessException.class);}@Test void shouldExpireOnlyAfterValidTo(){var a=qualification();a.approve("",2,ids);a.expire(0,ids);assertThat(a.status()).isEqualTo(QualificationStatus.VALID);}private static class Ids implements IdentifierGenerator{private final AtomicLong seq=new AtomicLong(1);public long nextId(){return seq.getAndIncrement();}public String nextBusinessNo(String prefix){return prefix+seq.getAndIncrement();}}}
